class UserTier(Enum):
    BASIC = "basic"
    SILVER = "silver"
    GOLD = "gold"
    PLATINUM = "platinum"
    ADMIN = "admin"


class OrderStatus(Enum):
    PENDING = "pending"
    CONFIRMED = "confirmed"
    FAILED = "failed"
    CANCELLED = "cancelled"


class DiscountType(Enum):
    PERCENTAGE = "percentage"
    FIXED = "fixed"


@dataclass
class CartItem:
    product_id: str
    name: str
    price: float
    quantity: int
    in_stock: bool = True
    max_quantity: int = 99


@dataclass
class User:
    user_id: str
    name: str
    email: str
    tier: UserTier
    payment_method: Optional[str] = "credit_card"
    balance: float = 10000.0


@dataclass
class DiscountCode:
    code: str
    discount_type: DiscountType
    value: float  # percentage (0-100) or fixed amount
    min_order_amount: float = 0.0
    allowed_tiers: list = field(default_factory=lambda: list(UserTier))
    is_admin_only: bool = False
    is_active: bool = True
