# Tax rates by state (simplified)
TAX_RATES = {
    "CA": 0.0725,
    "NY": 0.08,
    "TX": 0.0625,
    "FL": 0.06,
    "WA": 0.065,
    "OR": 0.0,  # Oregon has no sales tax
    "DEFAULT": 0.07,
}


def step1_validate_cart(cart_items: list[CartItem], user: User) -> dict:
    """
    Step 1: Validate cart items.
    Checks: non-empty cart, items in stock, valid quantities, valid prices.
    Returns validated cart summary.
    """
    print(f"\n{'='*60}")
    print(f"STEP 1: Validating Cart for user '{user.name}' ({user.tier.value})")
    print(f"{'='*60}")

    if not cart_items:
        raise CartValidationError("Cart is empty.")

    validated_items = []
    subtotal = 0.0
    errors = []

    for item in cart_items:
        item_errors = []

        if item.price <= 0:
            item_errors.append(f"Invalid price ({item.price}) for '{item.name}'")

        if item.quantity <= 0:
            item_errors.append(f"Invalid quantity ({item.quantity}) for '{item.name}'")

        if item.quantity > item.max_quantity:
            item_errors.append(
                f"Quantity ({item.quantity}) exceeds max ({item.max_quantity}) for '{item.name}'"
            )

        if not item.in_stock:
            item_errors.append(f"'{item.name}' is out of stock")

        if item_errors:
            errors.extend(item_errors)
        else:
            item_total = round(item.price * item.quantity, 2)
            subtotal += item_total
            validated_items.append({
                "product_id": item.product_id,
                "name": item.name,
                "price": item.price,
                "quantity": item.quantity,
                "item_total": item_total,
            })
            print(f"  ✓ {item.name} x{item.quantity} @ ${item.price:.2f} = ${item_total:.2f}")

    if errors:
        raise CartValidationError(
            f"Cart validation failed with {len(errors)} error(s): " + "; ".join(errors)
        )

    subtotal = round(subtotal, 2)
    print(f"\n  Subtotal: ${subtotal:.2f}")
    print(f"  ✓ Cart validated successfully ({len(validated_items)} items)")

    return {
        "validated_items": validated_items,
        "subtotal": subtotal,
        "item_count": len(validated_items),
        "user": user,
    }


def step2_apply_discount(
    cart_summary: dict, discount_code: Optional[str] = None
) -> dict:
    """
    Step 2: Validate user permissions and apply discount code.
    Checks: code existence, code active, user tier permissions, min order amount.
    Returns updated totals with discount applied.
    """
    print(f"\n{'='*60}")
    print(f"STEP 2: Applying Discount Code")
    print(f"{'='*60}")

    subtotal = cart_summary["subtotal"]
    user = cart_summary["user"]
    discount_amount = 0.0
    applied_code = None

    if discount_code is None:
        print("  No discount code provided. Skipping.")
        return {
            **cart_summary,
            "discount_amount": 0.0,
            "discount_code": None,
            "discounted_subtotal": subtotal,
        }

    discount_code = discount_code.strip().upper()
    print(f"  Attempting to apply code: '{discount_code}'")

    # Check if code exists
    if discount_code not in DISCOUNT_CODES:
        raise DiscountError(f"Discount code '{discount_code}' does not exist.")

    dc = DISCOUNT_CODES[discount_code]

    # Check if code is active
    if not dc.is_active:
        raise DiscountError(f"Discount code '{discount_code}' is no longer active.")

    # Check admin-only restriction
    if dc.is_admin_only and user.tier != UserTier.ADMIN:
        raise DiscountError(
            f"Discount code '{discount_code}' is restricted to admin users only. "
            f"Your tier: {user.tier.value}."
        )

    # Check user tier permission
    if user.tier not in dc.allowed_tiers:
        allowed = ", ".join(t.value for t in dc.allowed_tiers)
        raise DiscountError(
            f"Your tier '{user.tier.value}' is not eligible for code '{discount_code}'. "
            f"Allowed tiers: {allowed}."
        )

    # Check minimum order amount
    if subtotal < dc.min_order_amount:
        raise DiscountError(
            f"Minimum order amount for '{discount_code}' is ${dc.min_order_amount:.2f}. "
            f"Your subtotal: ${subtotal:.2f}."
        )

    # Calculate discount
    if dc.discount_type == DiscountType.PERCENTAGE:
        discount_amount = round(subtotal * (dc.value / 100.0), 2)
        if dc.max_discount is not None:
            discount_amount = min(discount_amount, dc.max_discount)
        print(f"  Percentage discount: {dc.value}% off ${subtotal:.2f}")
    elif dc.discount_type == DiscountType.FIXED:
        discount_amount = min(dc.value, subtotal)  # Can't discount more than subtotal
        print(f"  Fixed discount: ${dc.value:.2f} off")

    discount_amount = round(discount_amount, 2)
    discounted_subtotal = round(subtotal - discount_amount, 2)
    applied_code = discount_code

    print(f"  Discount amount: -${discount_amount:.2f}")
    print(f"  Discounted subtotal: ${discounted_subtotal:.2f}")
    print(f"  ✓ Discount code '{discount_code}' applied successfully")

    return {
        **cart_summary,
        "discount_amount": discount_amount,
        "discount_code": applied_code,
        "discounted_subtotal": discounted_subtotal,
    }


def step3_calculate_tax(
    discount_summary: dict, state: str = "DEFAULT"
) -> dict:
    """
    Step 3: Calculate tax on the discounted subtotal.
    Returns tax details and total before payment.
    """
    print(f"\n{'='*60}")
    print(f"STEP 3: Calculating Tax")
    print(f"{'='*60}")

    discounted_subtotal = discount_summary["discounted_subtotal"]
    state = state.upper()

    if discounted_subtotal < 0:
        raise TaxCalculationError("Taxable amount cannot be negative.")

    tax_rate = TAX_RATES.get(state, TAX_RATES["DEFAULT"])
    tax_amount = round(discounted_subtotal * tax_rate, 2)
    total = round(discounted_subtotal + tax_amount, 2)

    tax_info = TaxInfo(
        tax_rate=tax_rate,
        tax_amount=tax_amount,
        taxable_amount=discounted_subtotal,
    )

    state_label = state if state != "DEFAULT" else "Default"
    print(f"  State: {state_label}")
    print(f"  Tax rate: {tax_rate * 100:.2f}%")
    print(f"  Taxable amount: ${discounted_subtotal:.2f}")
    print(f"  Tax amount: ${tax_amount:.2f}")
    print(f"  Total (with tax): ${total:.2f}")
    print(f"  ✓ Tax calculated successfully")

    return {
        **discount_summary,
        "tax_info": tax_info,
        "total": total,
    }


def step4_process_payment(tax_summary: dict) -> dict:
    """
    Step 4: Process payment.
    Simulates payment processing with balance check.
    Returns payment result.
    """
    print(f"\n{'='*60}")
    print(f"STEP 4: Processing Payment")
    print(f"{'='*60}")

    user = tax_summary["user"]
    total = tax_summary["total"]

    if total <= 0:
        raise PaymentError("Payment amount must be greater than zero.")

    if not user.payment_method:
        raise PaymentError("No payment method on file for this user.")

    print(f"  Payment method: {user.payment_method}")
    print(f"  Amount to charge: ${total:.2f}")
    print(f"  User balance: ${user.balance:.2f}")

    # Simulate balance check
    if user.balance < total:
        payment_result = PaymentResult(
            success=False,
            transaction_id=None,
            amount_charged=0.0,
            message=f"Insufficient funds. Required: ${total:.2f}, Available: ${user.balance:.2f}",
        )
        raise PaymentError(payment_result.message)

    # Simulate successful payment
    transaction_id = f"TXN-{uuid.uuid4().hex[:12].upper()}"
    user.balance -= total  # Deduct from balance

    payment_result = PaymentResult(
        success=True,
        transaction_id=transaction_id,
        amount_charged=total,
        message="Payment processed successfully.",
    )

    print(f"  Transaction ID: {transaction_id}")
    print(f"  Amount charged: ${total:.2f}")
    print(f"  Remaining balance: ${user.balance:.2f}")
    print(f"  ✓ Payment processed successfully")

    return {
        **tax_summary,
        "payment_result": payment_result,
    }


def step5_create_order(payment_summary: dict) -> OrderRecord:
    """
    Step 5: Create the final order record.
    Returns a complete OrderRecord.
    """
    print(f"\n{'='*60}")
    print(f"STEP 5: Creating Order Record")
    print(f"{'='*60}")

    payment_result = payment_summary["payment_result"]

    if not payment_result.success:
        raise OrderCreationError("Cannot create order: payment was not successful.")

    order_id = f"ORD-{uuid.uuid4().hex[:8].upper()}"

    order = OrderRecord(
        order_id=order_id,
        user_id=payment_summary["user"].user_id,
        items=payment_summary["validated_items"],
        subtotal=payment_summary["subtotal"],
        discount_amount=payment_summary["discount_amount"],
        discount_code=payment_summary["discount_code"],
        tax_info=payment_summary["tax_info"],
        total=payment_summary["total"],
        payment=payment_result,
        status=OrderStatus.CONFIRMED,
        created_at=datetime.now().isoformat(),
    )

    print(f"  Order ID: {order.order_id}")
    print(f"  Status: {order.status.value}")
    print(f"  Created at: {order.created_at}")
    print(f"  ✓ Order created successfully")

    return order


def checkout(
    cart_items: list[CartItem],
    user: User,
    discount_code: Optional[str] = None,
    state: str = "DEFAULT",
) -> OrderRecord:
    """
    Multi-step checkout process.
    Each step depends on the output of the previous step.

    Steps:
        1. Validate cart items
        2. Apply discount codes (with permission validation)
        3. Calculate tax
        4. Process payment
        5. Create order record
    """
    print(f"\n{'#'*60}")
    print(f"  CHECKOUT PROCESS STARTED")
    print(f"  User: {user.name} | Tier: {user.tier.value}")
    print(f"  Discount Code: {discount_code or 'None'} | State: {state}")
    print(f"{'#'*60}")

    try:
        # Step 1: Validate cart
        cart_summary = step1_validate_cart(cart_items, user)

        # Step 2: Apply discount (depends on step 1 output)
        discount_summary = step2_apply_discount(cart_summary, discount_code)

        # Step 3: Calculate tax (depends on step 2 output)
        tax_summary = step3_calculate_tax(discount_summary, state)

        # Step 4: Process payment (depends on step 3 output)
        payment_summary = step4_process_payment(tax_summary)

        # Step 5: Create order record (depends on step 4 output)
        order = step5_create_order(payment_summary)

        print(f"\n{'#'*60}")
        print(f"  CHECKOUT COMPLETE")
        print(f"{'#'*60}")
        print_order_summary(order)

        return order

    except CheckoutError as e:
        print(f"\n  ✗ CHECKOUT FAILED at step '{e.step}': {e.message}")
        raise


def print_order_summary(order: OrderRecord):
    """Print a formatted order summary."""
    print(f"\n{'─'*60}")
    print(f"  ORDER SUMMARY")
    print(f"{'─'*60}")
    print(f"  Order ID:       {order.order_id}")
    print(f"  User ID:        {order.user_id}")
    print(f"  Status:         {order.status.value.upper()}")
    print(f"{'─'*60}")
    print(f"  Items:")
    for item in order.items:
        print(f"    • {item['name']} x{item['quantity']} @ ${item['price']:.2f} = ${item['item_total']:.2f}")
    print(f"{'─'*60}")
    print(f"  Subtotal:       ${order.subtotal:.2f}")
    if order.discount_code:
        print(f"  Discount ({order.discount_code}): -${order.discount_amount:.2f}")
    print(f"  Tax ({order.tax_info.tax_rate*100:.2f}%):     ${order.tax_info.tax_amount:.2f}")
    print(f"{'─'*60}")
    print(f"  TOTAL:          ${order.total:.2f}")
    print(f"{'─'*60}")
    print(f"  Transaction:    {order.payment.transaction_id}")
    print(f"  Created:        {order.created_at}")
    print(f"{'─'*60}")


